+#[derive(Serialize)]
+struct ValidateReport {
+    skill: String,
+    path: String,
+    warnings: Vec<WarningOutput>,
+    ubs: Option<UbsReport>,
+    clean: bool,
+}
+
+#[derive(Serialize)]
+struct WarningOutput {
+    field: String,
+    message: String,
+}
+
+#[derive(Serialize)]
+struct UbsReport {
+    exit_code: i32,
+    findings: usize,
+    clean: bool,
+    stdout: String,
+    stderr: String,
+    items: Vec<UbsFindingOutput>,
+}
+
+#[derive(Serialize)]
+struct UbsFindingOutput {
+    category: String,
+    severity: String,
+    file: String,
+    line: u32,
+    column: u32,
+    message: String,
+    suggested_fix: Option<String>,
+}
+
+fn build_report(
+    skill: &str,
+    skill_md: &std::path::Path,
+    warnings: &[ValidationWarning],
+    ubs_result: Option<&UbsResult>,
+) -> ValidateReport {
+    let warning_items = warnings
+        .iter()
+        .map(|warning| WarningOutput {
+            field: warning.field.clone(),
+            message: warning.message.clone(),
+        })
+        .collect::<Vec<_>>();
+    let ubs = ubs_result.map(|result| UbsReport {
+        exit_code: result.exit_code,
+        findings: result.findings.len(),
+        clean: result.is_clean(),
+        stdout: result.stdout.clone(),
+        stderr: result.stderr.clone(),
+        items: result
+            .findings
+            .iter()
+            .map(map_finding)
+            .collect::<Vec<_>>(),
+    });
